from __future__ import annotations

from dataclasses import dataclass, replace
from decimal import Decimal
from typing import Dict, Tuple


class ShoppingCartError(Exception):
    """Base exception for shopping cart errors."""


class InvalidProductNameError(ShoppingCartError):
    """Raised when a product name is empty or invalid."""


class InvalidUnitPriceError(ShoppingCartError):
    """Raised when a unit price is invalid."""


class InvalidQuantityError(ShoppingCartError):
    """Raised when an item quantity is invalid."""


class ItemNotFoundError(ShoppingCartError):
    """Raised when an item does not exist in the cart."""


class UnitPriceMismatchError(ShoppingCartError):
    """Raised when adding an existing item with a different unit price."""


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount is invalid."""


@dataclass(frozen=True)
class CartItem:
    """Represents a single item in a shopping cart."""

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def line_total(self) -> Decimal:
        """Return the total price for this cart item before discounts."""
        return self.unit_price * self.quantity


class ShoppingCart:
    """Manage shopping cart items, discounts, and totals."""

    def __init__(self) -> None:
        self._items: Dict[str, CartItem] = {}
        self._discount_amount: Decimal = Decimal("0")

    def add_item(
        self,
        product_name: str,
        unit_price: Decimal,
        quantity: int = 1,
    ) -> None:
        """Add an item to the cart or increase its quantity if it already exists."""
        normalized_name = self._validate_product_name(product_name)
        self._validate_unit_price(unit_price)
        self._validate_positive_quantity(quantity)

        existing_item = self._items.get(normalized_name)

        if existing_item is None:
            self._items[normalized_name] = CartItem(
                product_name=normalized_name,
                unit_price=unit_price,
                quantity=quantity,
            )
            return

        if existing_item.unit_price != unit_price:
            raise UnitPriceMismatchError(
                f"Product '{normalized_name}' already exists with unit price "
                f"{existing_item.unit_price}, not {unit_price}."
            )

        self._items[normalized_name] = replace(
            existing_item,
            quantity=existing_item.quantity + quantity,
        )

    def remove_item(self, product_name: str) -> CartItem:
        """Remove an item from the cart by product name and return it."""
        normalized_name = self._validate_product_name(product_name)
        self._ensure_item_exists(normalized_name)

        return self._items.pop(normalized_name)

    def update_quantity(self, product_name: str, quantity: int) -> None:
        """Update the quantity of an existing cart item."""
        normalized_name = self._validate_product_name(product_name)
        self._validate_positive_quantity(quantity)

        item = self._get_item(normalized_name)
        self._items[normalized_name] = replace(item, quantity=quantity)

    def calculate_subtotal(self) -> Decimal:
        """Calculate the cart subtotal before discounts."""
        return sum(
            (item.line_total for item in self._items.values()),
            start=Decimal("0"),
        )

    def apply_percentage_discount(self, percentage: Decimal) -> None:
        """Apply a percentage discount to the current subtotal."""
        if percentage < Decimal("0") or percentage > Decimal("100"):
            raise InvalidDiscountError(
                "Percentage discount must be between 0 and 100 inclusive."
            )

        self._discount_amount = self.calculate_subtotal() * percentage / Decimal("100")

    def apply_flat_discount(self, amount: Decimal) -> None:
        """Apply a flat discount amount to the cart."""
        if amount < Decimal("0"):
            raise InvalidDiscountError("Flat discount amount cannot be negative.")

        subtotal = self.calculate_subtotal()

        if amount > subtotal:
            raise InvalidDiscountError(
                f"Flat discount amount {amount} cannot exceed subtotal {subtotal}."
            )

        self._discount_amount = amount

    def calculate_total(self) -> Decimal:
        """Calculate the final cart total after discounts."""
        subtotal = self.calculate_subtotal()
        return max(subtotal - self._discount_amount, Decimal("0"))

    def list_items(self) -> Tuple[CartItem, ...]:
        """Return all cart items with their details."""
        return tuple(self._items.values())

    def clear(self) -> None:
        """Remove all items and discounts from the cart."""
        self._items.clear()
        self._discount_amount = Decimal("0")

    def _get_item(self, product_name: str) -> CartItem:
        self._ensure_item_exists(product_name)
        return self._items[product_name]

    def _ensure_item_exists(self, product_name: str) -> None:
        if product_name not in self._items:
            raise ItemNotFoundError(f"Product '{product_name}' is not in the cart.")

    @staticmethod
    def _validate_product_name(product_name: str) -> str:
        normalized_name = product_name.strip()

        if not normalized_name:
            raise InvalidProductNameError("Product name cannot be empty.")

        return normalized_name

    @staticmethod
    def _validate_unit_price(unit_price: Decimal) -> None:
        if unit_price < Decimal("0"):
            raise InvalidUnitPriceError("Unit price cannot be negative.")

    @staticmethod
    def _validate_positive_quantity(quantity: int) -> None:
        if quantity <= 0:
            raise InvalidQuantityError("Quantity must be greater than zero.")
